import { GoogleGenAI, Type } from "@google/genai";
import { Contributor, Transaction } from '../types';
import { Logger, Metrics } from './monitoringService';

const getAIClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Utilitário de re-tentativa com backoff exponencial agressivo para lidar com Rate Limits (429)
 * Aumentado para 5 tentativas com delay base de 4s
 */
async function callWithRetry(fn: () => Promise<any>, retries = 5, delay = 4000): Promise<any> {
    try {
        return await fn();
    } catch (error: any) {
        const errorMessage = error?.message?.toLowerCase() || "";
        const isQuotaError = errorMessage.includes("429") || errorMessage.includes("quota") || errorMessage.includes("limit") || errorMessage.includes("403") || errorMessage.includes("exceeded");

        if (retries > 0 && isQuotaError) {
            // Aumenta o fator de multiplicação para espaçar mais as tentativas (4s -> 9s -> 19s...)
            const nextDelay = delay * 2 + Math.random() * 1500; 
            console.warn(`[IA] Limite de cota atingido. Tentando novamente em ${Math.round(nextDelay)}ms... (Tentativas restantes: ${retries})`);
            await new Promise(r => setTimeout(r, nextDelay));
            return callWithRetry(fn, retries - 1, nextDelay);
        }
        throw error;
    }
}

/**
 * INFERÊNCIA INICIAL: Usa o modelo Flash para estruturação inicial rápida.
 */
export const performInitialInference = async (rawRows: string[][]): Promise<any[]> => {
    const ai = getAIClient();
    const indexedRows = rawRows.map((row, index) => ({ originalIndex: index, data: row }));

    const instructions = `
        VOCÊ É UM EXTRATOR FINANCEIRO ESPECIALISTA.
        Transforme as linhas recebidas em objetos JSON estruturados.

        REGRAS:
        - date: Formato YYYY-MM-DD
        - name: Nome ou Descrição limpa (remova códigos, IDs e termos bancários como TED/PIX)
        - amount: Valor numérico puro (ponto para decimal, negativo para saídas)
        - originalIndex: Mantenha exatamente o índice fornecido.
    `;

    return callWithRetry(async () => {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Mapeie estas linhas preservando o originalIndex: ${JSON.stringify(indexedRows)}`,
            config: {
                systemInstruction: instructions,
                temperature: 0.1,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            date: { type: Type.STRING },
                            name: { type: Type.STRING },
                            amount: { type: Type.STRING },
                            originalIndex: { type: Type.INTEGER }
                        },
                        required: ["date", "name", "amount", "originalIndex"]
                    }
                }
            }
        });
        return response.text ? JSON.parse(response.text) : [];
    });
};

/**
 * MOTOR DE APRENDIZADO: Usa o modelo Pro para casos complexos.
 */
export const learnAndTransformFile = async (
    rawRows: string[][],
    manualCorrections: Array<{ originalRow: string[], corrected: { date: string, name: string, amount: string } }>
): Promise<any[]> => {
    const ai = getAIClient();

    const indexedRows = rawRows.map((row, index) => ({ 
        originalIndex: index, 
        content: row 
    }));

    const examplesPrompt = manualCorrections.map((ex, i) => `
        EXEMPLO #${i + 1}:
        ENTRADA: ${JSON.stringify(ex.originalRow)}
        CORRETO: Data="${ex.corrected.date}", Nome="${ex.corrected.name}", Valor="${ex.corrected.amount}"
    `).join('\n');

    const instructions = `
        Utilize os exemplos fornecidos para aprender o padrão de extração deste arquivo.
        Aplique o mesmo padrão em todas as outras linhas.
        ${examplesPrompt}
    `;

    return callWithRetry(async () => {
        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview',
            contents: `Processe: ${JSON.stringify(indexedRows)}`,
            config: {
                systemInstruction: instructions,
                temperature: 0,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            date: { type: Type.STRING },
                            name: { type: Type.STRING },
                            amount: { type: Type.STRING },
                            originalIndex: { type: Type.INTEGER }
                        },
                        required: ["date", "name", "amount", "originalIndex"]
                    }
                }
            }
        });
        return response.text ? JSON.parse(response.text) : [];
    });
};

