                                            className={`h-full transition-all duration-300 ${coolingDownSeconds > 0 ? 'bg-amber-500' : 'bg-indigo-600'}`} 
                                            style={{ width: `${(progress.current/progress.total)*100}%` }}
                                        ></div>
