                                                        onChange={(e) => updateRowField(row.id, 'date', e.target.value)} 
                                                        className="w-full bg-transparent border-none outline-none font-mono text-[11px] font-bold text-slate-600 dark:text-slate-400 focus:text-indigo-600" 
                                                    />
